// Concatenates content/knowledge/*.md (fixed order) into lib/knowledge.generated.ts.
// Run as `predev` and `prebuild`. The generated file is git-ignored — it's a
// build artifact, byte-identical across builds so the system prompt (and its
// Anthropic prompt cache) stays stable.

import { readFileSync, writeFileSync, mkdirSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const root = join(dirname(fileURLToPath(import.meta.url)), "..");

// Fixed order — do not reorder without re-checking the token budget (~8k target).
const FILES = [
  "resume.md",
  "bio.md",
  "projects-adarle20.md",
  "projects-nokia.md",
  "projects-dell.md",
  "faq.md",
];

const parts = FILES.map((name) =>
  readFileSync(join(root, "content", "knowledge", name), "utf8").trim(),
);

// Join with blank-line separators between files.
const knowledge = parts.join("\n\n");

// JSON.stringify escapes backticks, ${, backslashes, and newlines safely —
// avoids the fragility of hand-escaping a template literal.
const out = `// AUTO-GENERATED by scripts/build-knowledge.mjs — do not edit by hand.
export const KNOWLEDGE_BASE = ${JSON.stringify(knowledge)};
`;

const target = join(root, "lib", "knowledge.generated.ts");
mkdirSync(dirname(target), { recursive: true });
writeFileSync(target, out, "utf8");

console.log(
  `[build-knowledge] wrote ${target} (${knowledge.length} chars from ${FILES.length} files)`,
);
